SELECT COUNT(*)
FROM report
WHERE reporter_id = #{reporterId}
  AND target_type = #{targetType}
  AND target_id = #{targetId}
  AND status != 'rejected'

SELECT r.*, u.nickname as reporterName, tu.nickname as targetUserName, au.nickname as adminName, CASE r.target_type WHEN 'article' THEN a.title WHEN 'comment' THEN CONCAT('评论: ', SUBSTRING(c.content, 1, 50)) WHEN 'user' THEN CONCAT('用户: ', tu.nickname) ELSE '未知' END as targetTitle FROM report r LEFT JOIN user u ON r.reporter_id = u.id LEFT JOIN user tu ON r.target_user_id = tu.id LEFT JOIN user au ON r.admin_id = au.id LEFT JOIN article a ON r.target_type = 'article' AND r.target_id = a.id LEFT JOIN comment c ON r.target_type = 'comment' AND r.target_id = c.id
1=1
AND r.status = #{status}
AND r.target_type = #{targetType}
ORDER BY r.created_at DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*)
FROM report r

    1=1

        AND r.status = #{status}


        AND r.target_type = #{targetType}
